import { useEffect, useState } from "react";

import { apiClient } from "@/App";

import { Button } from "@/components/ui/button";

import { toast } from "sonner";

import {
  Shield,
  CheckCircle,
  XCircle,
  Clock,
  Ban,
} from "lucide-react";

const LoginPortalPage = () => {

  const [loading, setLoading] = useState(true);

  const [users, setUsers] = useState([]);

  // =====================================
  // LOAD PENDING USERS
  // =====================================

  const fetchPendingUsers = async () => {
    try {

      setLoading(true);

      const response = await apiClient.get(
        "/admin/pending-users"
      );

      setUsers(response.data || []);

    } catch (error) {

      console.error(error);

      toast.error(
        "Failed to load login requests"
      );

    } finally {

      setLoading(false);

    }
  };

  useEffect(() => {
    fetchPendingUsers();
  }, []);

  // =====================================
  // APPROVE USER
  // =====================================

  const approveUser = async (userId) => {
    try {

      await apiClient.put(
        `/admin/approve-user/${userId}`
      );

      toast.success("User approved");

      fetchPendingUsers();

    } catch (error) {

      console.error(error);

      toast.error("Approval failed");

    }
  };

  // =====================================
  // REJECT USER
  // =====================================

  const rejectUser = async (userId) => {
    try {

      await apiClient.put(
        `/admin/reject-user/${userId}`
      );

      toast.success("User rejected");

      fetchPendingUsers();

    } catch (error) {

      console.error(error);

      toast.error("Rejection failed");

    }
  };

  // =====================================
  // BLOCK USER
  // =====================================

  const blockUser = async (userId) => {
    try {

      await apiClient.put(
        `/admin/block-user/${userId}`
      );

      toast.success("User blocked");

      fetchPendingUsers();

    } catch (error) {

      console.error(error);

      toast.error("Blocking failed");

    }
  };

  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex items-center gap-3">

        <div className="w-12 h-12 rounded-xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center">
          <Shield className="w-6 h-6 text-emerald-400" />
        </div>

        <div>
          <h1 className="text-2xl font-bold text-white">
            Login Approval Portal
          </h1>

          <p className="text-slate-400 text-sm">
            Approve or reject school system access
          </p>
        </div>

      </div>

      {/* CONTENT */}
      <div className="bg-[#0F172A] border border-white/5 rounded-2xl overflow-hidden">

        {loading ? (

          <div className="p-10 text-center text-slate-400">
            Loading requests...
          </div>

        ) : users.length === 0 ? (

          <div className="p-10 text-center">

            <Clock className="w-10 h-10 mx-auto text-slate-500 mb-3" />

            <p className="text-slate-400">
              No pending login requests
            </p>

          </div>

        ) : (

          <div className="divide-y divide-white/5">

            {users.map((user) => (

              <div
                key={user.id || user._id}
                className="p-5 flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4"
              >

                {/* USER INFO */}
                <div>

                  <h3 className="text-white font-semibold">
                    {user.full_name || "Unknown User"}
                  </h3>

                  <p className="text-slate-400 text-sm">
                    {user.email}
                  </p>

                  <div className="flex gap-2 mt-2 flex-wrap">

                    <span className="px-2 py-1 rounded bg-emerald-500/10 text-emerald-400 text-xs uppercase">
                      {user.role}
                    </span>

                    <span className="px-2 py-1 rounded bg-yellow-500/10 text-yellow-400 text-xs uppercase">
                      {user.approval_status || "pending"}
                    </span>

                  </div>

                </div>

                {/* ACTIONS */}
                <div className="flex gap-2 flex-wrap">

                  <Button
                    onClick={() =>
                      approveUser(user.id || user._id)
                    }
                    className="bg-emerald-600 hover:bg-emerald-700"
                  >
                    <CheckCircle className="w-4 h-4 mr-2" />
                    Approve
                  </Button>

                  <Button
                    variant="destructive"
                    onClick={() =>
                      rejectUser(user.id || user._id)
                    }
                  >
                    <XCircle className="w-4 h-4 mr-2" />
                    Reject
                  </Button>

                  <Button
                    variant="outline"
                    onClick={() =>
                      blockUser(user.id || user._id)
                    }
                  >
                    <Ban className="w-4 h-4 mr-2" />
                    Block
                  </Button>

                </div>

              </div>

            ))}

          </div>

        )}

      </div>

    </div>
  );
};

export default LoginPortalPage;
